    public static IHtmlContent Icon(this IHtmlHelper _, string name, int size = 18, string? cssClass = null)
    {
        var inner = Paths.TryGetValue(name, out var p) ? p : Paths["hash"];
        var cls = string.IsNullOrEmpty(cssClass) ? "icon" : $"icon {cssClass}";
        var svg = $"<svg class=\"{cls}\" width=\"{size}\" height=\"{size}\" viewBox=\"0 0 24 24\" fill=\"none\" " +
                  "stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" " +
                  $"aria-hidden=\"true\" focusable=\"false\">{inner}</svg>";
        return new HtmlString(svg);
    }
